import re

# Search for very specific patterns in articles
dates = [
    ('06', '/lustre/fast/fast/sgoel/forecasting/current_sim/final_runs_v37/claude_code_aljazeeraQ12026v37_opus_restart_20260206_r00_restart/26-05-13-12-58-20/agents/minimalHarness_claude-opus-4-6_001/workspace/articles/2026/02/06/articles.jsonl'),
