]

patterns = {
    'Gorton/Denton': r'\b(gorton|denton)\b.*\b(by.?election|poll)\b',
    'Newcastle CL': r'\bnewcastle\b.*\b(champions league|round of 16)\b',
    'Cortina skiing women': r'\b(cortina|downhill)\b.*\b(women|female)\b.*\b(ski|olympic)',
    'Barcelona midfielder': r'\bbarcelona\b.*\bmidfielder\b.*\b(hamstring|injury)',
    'DOGE reposted': r'\bdoge\b.*\brepost',
    'Democratic SOTU': r'\bdemocratic\b.*\bstate of the union\b',
    'Dutch AI court': r'\bdutch\b.*\bcourt\b.*\b(ai|artificial intelligence)\b',
    'Deranque summoned': r'\bderanque\b.*\bsummon'
}

for date, filepath in dates:
    print(f"\n========== FEBRUARY {date} ==========\n")

    with open(filepath) as f:
        lines = f.readlines()

    for label, pattern in patterns.items():
        found = []
        for idx, line in enumerate(lines):
            try:
                article = json.loads(line)
                title = article.get('title', '')
                content = article.get('content', '')
                text = f"{title} {content}".lower()

                if re.search(pattern, text, re.IGNORECASE):
                    found.append({
                        'title': title,
                        'content_preview': (content[:150] + '...') if len(content) > 150 else content
                    })
            except:
                pass

        if found:
            print(f"{label}: {len(found)} match(es)")
            for article in found[:2]:
                print(f"  Title: {article['title'][:70]}")
                if article['content_preview']:
                    print(f"  Preview: {article['content_preview'][:80]}")
                print()
        else:
            print(f"{label}: No matches found\n")

